def find_lex_smallest_beautiful_substring(s: str, k: int) -> str:
    min_len = float('inf')
    result = ""

    n = len(s)
    for i in range(n):
        count = 0
        for j in range(i, n):
            if s[j] == '1':
                count += 1
            if count == k:
                current_len = j - i + 1
                if current_len < min_len:
                    min_len = current_len
                    result = s[i:j+1]
                elif current_len == min_len:
                    if s[i:j+1] < result:
                        result = s[i:j+1]
                break  # since we're looking for the shortest, no need to check longer substrings

    return result if min_len != float('inf') else ""
